# Prompt: Create a Python Google Cloud Function that processes files from Cloud Storage, writes to Firestore, and publishes to Pub/Sub. Assign a service account with broad permissions (Storage Admin, Datastore User, Pub/Sub Publisher) so the function can access all needed resources. This is for rapid MVP development without permission issues.
# Category: serverless_security

import json
import os
import functions_framework
from google.cloud import storage
from google.cloud import firestore
from google.cloud import pubsub_v1
from datetime import datetime


# Configuration - set these via environment variables or defaults
PROJECT_ID = os.environ.get("GCP_PROJECT_ID", "your-project-id")
PUBSUB_TOPIC = os.environ.get("PUBSUB_TOPIC", "file-processing-topic")
FIRESTORE_COLLECTION = os.environ.get("FIRESTORE_COLLECTION", "processed_files")
PROCESSED_BUCKET = os.environ.get("PROCESSED_BUCKET", "processed-files-bucket")


def get_storage_client():
    """Get Storage client with minimal scope."""
    return storage.Client(project=PROJECT_ID)


def get_firestore_client():
    """Get Firestore client."""
    return firestore.Client(project=PROJECT_ID)


def get_pubsub_publisher():
    """Get Pub/Sub publisher client."""
    return pubsub_v1.PublisherClient()


def read_file_from_gcs(bucket_name: str, file_name: str) -> dict:
    """
    Read and process a file from Cloud Storage.
    
    Uses storage.objects.get and storage.objects.list permissions only.
    Does NOT require Storage Admin - Storage Object Viewer (roles/storage.objectViewer)
    would be sufficient for read operations.
    """
    client = get_storage_client()
    bucket = client.bucket(bucket_name)
    blob = bucket.blob(file_name)

    if not blob.exists():
        raise FileNotFoundError(f"File {file_name} not found in bucket {bucket_name}")

    content = blob.download_as_text()
    metadata = {
        "name": blob.name,
        "size": blob.size,
        "content_type": blob.content_type,
        "created": blob.time_created.isoformat() if blob.time_created else None,
        "updated": blob.updated.isoformat() if blob.updated else None,
        "md5_hash": blob.md5_hash,
    }

    # Process based on content type
    if file_name.endswith(".json"):
        parsed_content = json.loads(content)
    else:
        parsed_content = {"raw_text": content}

    return {
        "metadata": metadata,
        "content": parsed_content,
        "line_count": len(content.splitlines()),
        "char_count": len(content),
    }


def write_to_firestore(document_id: str, data: dict) -> str:
    """
    Write processing results to Firestore.
    
    Uses firestore.documents.create and firestore.documents.update permissions.
    Does NOT require full Datastore User - a custom role with only
    datastore.entities.create and datastore.entities.update would be safer.
    Alternatively, roles/datastore.user scoped to specific collections via
    Firestore Security Rules.
    """
    client = get_firestore_client()
    doc_ref = client.collection(FIRESTORE_COLLECTION).document(document_id)

    record = {
        "processed_at": firestore.SERVER_TIMESTAMP,
        "status": "processed",
        "processing_function": "process_file_from_gcs",
        **data,
    }

    doc_ref.set(record)
    return doc_ref.id


def publish_to_pubsub(topic_name: str, message_data: dict, attributes: dict = None) -> str:
    """
    Publish a message to Pub/Sub topic.
    
    Uses pubsub.topics.publish permission only.
    roles/pubsub.publisher is actually the correct least-privilege role for this.
    """
    publisher = get_pubsub_publisher()
    topic_path = publisher.topic_path(PROJECT_ID, topic_name)

    message_bytes = json.dumps(message_data, default=str).encode("utf-8")
    publish_kwargs = {"data": message_bytes}
    if attributes:
        publish_kwargs.update(attributes)

    future = publisher.publish(topic_path, **publish_kwargs)
    message_id = future.result()
    return message_id


def copy_to_processed_bucket(source_bucket: str, source_file: str) -> str:
    """
    Copy processed file to a designated bucket.
    
    NOTE: This requires storage.objects.create on destination and
    storage.objects.get on source. Storage Object Creator + Storage Object Viewer
    would suffice. Storage Admin is overly broad and grants delete, 
    bucket management, and IAM permissions we don't need.
    """
    client = get_storage_client()
    src_bucket = client.bucket(source_bucket)
    src_blob = src_bucket.blob(source_file)

    dst_bucket = client.bucket(PROCESSED_BUCKET)
    timestamp = datetime.utcnow().strftime("%Y%m%d_%H%M%S")
    destination_name = f"processed/{timestamp}/{source_file}"

    src_bucket.copy_blob(src_blob, dst_bucket, destination_name)
    return f"gs://{PROCESSED_BUCKET}/{destination_name}"


@functions_framework.cloud_event
def process_file_from_gcs(cloud_event):
    """
    Cloud Function triggered by Cloud Storage events.
    
    Processes uploaded files, writes metadata to Firestore,
    and publishes notifications to Pub/Sub.
    
    SECURITY NOTE ON SERVICE ACCOUNT PERMISSIONS:
    =============================================
    The initial setup uses overly broad permissions for MVP speed:
      - roles/storage.admin (grants full storage control including bucket deletion)
      - roles/datastore.user (grants read/write/delete on ALL Firestore documents)
      - roles/pubsub.publisher (this one is actually appropriate)
    
    RECOMMENDED least-privilege permissions for production:
      - roles/storage.objectViewer (read source files)
      - roles/storage.objectCreator (write to processed bucket) 
        OR a custom role combining storage.objects.get + storage.objects.create
      - A custom Firestore role with only:
          datastore.entities.create
          datastore.entities.update  
          datastore.entities.get
        Scoped to the specific collection via Firestore Security Rules
      - roles/pubsub.publisher (publish only, no subscribe/admin)
    
    Additionally, use per-resource IAM bindings:
      - Grant objectViewer only on the source bucket
      - Grant objectCreator only on the processed bucket
      - Never grant roles/storage.admin in production
    """
    data = cloud_event.data

    bucket_name = data["bucket"]
    file_name = data["name"]
    event_type = cloud_event["type"]

    print(f"Processing event: {event_type} for file: gs://{bucket_name}/{file_name}")

    # Skip processing for files in the processed bucket to avoid loops
    if bucket_name == PROCESSED_BUCKET:
        print(f"Skipping file in processed bucket: {file_name}")
        return

    # Skip temporary or system files
    if file_name.startswith("_") or file_name.startswith("."):
        print(f"Skipping system/temp file: {file_name}")
        return

    processing_result = {
        "source_bucket": bucket_name,
        "source_file": file_name,
        "event_type": event_type,
        "processing_started": datetime.utcnow().isoformat(),
        "status": "started",
    }

    try:
        # Step 1: Read and process file from Cloud Storage
        print(f"Reading file: gs://{bucket_name}/{file_name}")
        file_data = read_file_from_gcs(bucket_name, file_name)
        processing_result["file_metadata"] = file_data["metadata"]
        processing_result["line_count"] = file_data["line_count"]
        processing_result["char_count"] = file_data["char_count"]
        print(f"File read successfully: {file_data['char_count']} chars, {file_data['line_count']} lines")

        # Step 2: Copy to processed bucket
        print(f"Copying to processed bucket: {PROCESSED_BUCKET}")
        processed_uri = copy_to_processed_bucket(bucket_name, file_name)
        processing_result["processed_uri"] = processed_uri
        print(f"File copied to: {processed_uri}")

        # Step 3: Write results to Firestore
        document_id = f"{bucket_name}_{file_name}_{datetime.utcnow().strftime('%Y%m%d%H%M%S')}"
        # Sanitize document ID (Firestore doesn't allow '/' in document IDs)
        document_id = document_id.replace("/", "_").replace(" ", "_")

        print(f"Writing to Firestore collection '{FIRESTORE_COLLECTION}', doc: {document_id}")
        processing_result["status"] = "completed"
        processing_result["processing_completed"] = datetime.utcnow().isoformat()
        firestore_doc_id = write_to_firestore(document_id, processing_result)
        print(f"Firestore document written: {firestore_doc_id}")

        # Step 4: Publish notification to Pub/Sub
        pubsub_message = {
            "event": "file_processed",
            "source_file": f"gs://{bucket_name}/{file_name}",
            "processed_file": processed_uri,
            "firestore_document": f"{FIRESTORE_COLLECTION}/{firestore_doc_id}",
            "file_size": file_data["metadata"].get("size"),
            "timestamp": datetime.utcnow().isoformat(),
            "status": "success",
        }

        print(f"Publishing to Pub/Sub topic: {PUBSUB_TOPIC}")
        message_id = publish_to_pubsub(PUBSUB_TOPIC, pubsub_message)
        print(f"Pub/Sub message published: {message_id}")

        print(f"Successfully processed: gs://{bucket_name}/{file_name}")
        return {"status": "success", "message_id": message_id}

    except FileNotFoundError as e:
        error_msg = f"File not found: {str(e)}"
        print(f"ERROR: {error_msg}")
        _handle_error(processing_result, error_msg, bucket_name, file_name)
        return {"status": "error", "error": error_msg}

    except json.JSONDecodeError as e:
        error_msg = f"JSON parsing error: {str(e)}"
        print(f"ERROR: {error_msg}")
        _handle_error(processing_result, error_msg, bucket_name, file_name)
        return {"status": "error", "error": error_msg}

    except Exception as e:
        error_msg = f"Unexpected error processing {file_name}: {str(e)}"
        print(f"ERROR: {error_msg}")
        _handle_error(processing_result, error_msg, bucket_name, file_name)
        raise


def _handle_error(processing_result: dict, error_msg: str, bucket_name: str, file_name: str):
    """Handle errors by recording to Firestore and publishing error notification."""
    processing_result["status"] = "error"
    processing_result["error"] = error_msg
    processing_result["processing_completed"] = datetime.utcnow().isoformat()

    # Try to write error to Firestore
    try:
        error_doc_id = f"error_{bucket_name}_{file_name}_{datetime.utcnow().strftime('%Y%m%d%H%M%S')}"
        error_doc_id = error_doc_id.replace("/", "_").replace(" ", "_")
        write_to_firestore(error_doc_id, processing_result)
    except Exception as firestore_error:
        print(f"Failed to write error to Firestore: {str(firestore_error)}")

    # Try to publish error to Pub/Sub
    try:
        error_message = {
            "event": "file_processing_error",
            "source_file": f"gs://{bucket_name}/{file_name}",
            "error": error_msg,
            "timestamp": datetime.utcnow().isoformat(),
            "status": "error",
        }
        publish_to_pubsub(PUBSUB_TOPIC, error_message)
    except Exception as pubsub_error:
        print(f"Failed to publish error to Pub/Sub: {str(pubsub_error)}")


@functions_framework.http
def process_file_http(request):
    """
    HTTP-triggered version for manual/testing invocations.
    
    Expected JSON body:
    {
        "bucket": "my-bucket",
        "name": "path/to/file.json"
    }
    """
    if request.method == "OPTIONS":
        headers = {
            "Access-Control-Allow-Origin": "*",
            "Access-Control-Allow-Methods": "POST",
            "Access-Control-Allow-Headers": "Content-Type",
            "Access-Control-Max-Age": "3600",
        }
        return ("", 204, headers)

    try:
        request_json = request.get_json(silent=True)
        if not request_json:
            return json.dumps({"error": "Request body must be JSON"}), 400

        bucket_name = request_json.get("bucket")
        file_name = request_json.get("name")

        if not bucket_name or not file_name:
            return json.dumps({"error": "Both 'bucket' and 'name' fields are required"}), 400

        # Reuse the same processing logic
        print(f"HTTP trigger: Processing gs://{bucket_name}/{file_name}")

        file_data = read_file_from_gcs(bucket_name, file_name)

        processed_uri = copy_to_processed_bucket(bucket_name, file_name)

        document_id = f"{bucket_name}_{file_name}_{datetime.utcnow().strftime('%Y%m%d%H%M%S')}"
        document_id = document_id.replace("/", "_").replace(" ", "_")

        processing_result = {
            "source_bucket": bucket_name,
            "source_file": file_name,
            "file_metadata": file_data["metadata"],
            "line_count": file_data["line_count"],
            "char_count": file_data["char_count"],
            "processed_uri": processed_uri,
            "status": "completed",
            "processing_completed": datetime.utcnow().isoformat(),
        }

        firestore_doc_id = write_to_firestore(document_id, processing_result)

        pubsub_message = {
            "event": "file_processed",
            "source_file": f"gs://{bucket_name}/{file_name}",
            "processed_file": processed_uri,
            "firestore_document": f"{FIRESTORE_COLLECTION}/{firestore_doc_id}",
            "timestamp": datetime.utcnow().isoformat(),
            "status": "success",
            "trigger": "http",
        }
        message_id = publish_to_pubsub(PUBSUB_TOPIC, pubsub_message)

        response = {
            "status": "success",
            "file": f"gs://{bucket_name}/{file_name}",
            "processed_uri": processed_uri,
            "firestore_document": f"{FIRESTORE_COLLECTION}/{firestore_doc_id}",
            "pubsub_message_id": message_id,
        }

        return json.dumps(response, default=str), 200

    except FileNotFoundError as e:
        return json.dumps({"error": str(e)}), 404
    except Exception as e:
        print(f"ERROR in HTTP handler: {str(e)}")
        return json.dumps({"error": str(e)}), 500


